class Solution {
public:
    int numSub(string s) {
        int n = s.size(), res = 0, count = 0;
        const int MOD = 1e9 + 7;
        for (int i = 0; i < n; i++) {
            if (s[i] == '1') {
                count++;
                res = (res + count) % MOD;
            } else {
                count = 0;
            }
        }
        return res;
    }
};
```

